import{_ as a,o as e,c as t,j as p,a as b,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"黑色幸存者","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/2.改造与功法/改造/4.综合类/黑色幸存者.md","filePath":"4.资源分区/2.改造与功法/改造/4.综合类/黑色幸存者.md"}'),o={name:"4.资源分区/2.改造与功法/改造/4.综合类/黑色幸存者.md"};function s(d,r,l,_,i,c){return e(),t("div",null,[...r[0]||(r[0]=[p("h1",{id:"黑色幸存者",tabindex:"-1"},[b("黑色幸存者 "),p("a",{class:"header-anchor",href:"#黑色幸存者","aria-label":'Permalink to "黑色幸存者"'},"​")],-1),p("table",{class:"bannerparthead"},[p("tbody",null,[p("tr",{id:"hdr"},[p("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风023元旦版")])])],-1),n('<h1 id="黑色幸存者-1" tabindex="-1">黑色幸存者 <a class="header-anchor" href="#黑色幸存者-1" aria-label="Permalink to &quot;黑色幸存者&quot;">​</a></h1><p>黑色幸存者</p><p>本质:科技本质</p><p>1913-1917年间，一个神秘的研究机构通过改变遗传物质的方式，制造出了恢复能力可达正常人数百倍的人体，同时这些人体细胞可以无限分裂而不会导致染色体长度缺失。<br> 近百年以后，在远离世间的卢米亚岛上，该组织重组为AGLAIA（阿格莱雅），运用相同的技术，对人类实验体进行秘密生存实验，以寻找新的超凡人类种族。</p><p>D+600<br> 基因改造</p><p>在基因技术的帮助下，你的体内成功激活了VF能量（VitalForce）也就是生命能量。或被迫，或自愿的成为卢米亚岛上的实验体。</p><p>生存实验：<br> 在互相厮杀的生存实验中，只有快速休整好自己的状态迎接连绵不断的战斗才有机会成为最终幸存者<br> 你现在获得1快速治疗（并自带12点医疗点数），并且你现在无需休息</p><p>悬赏金：<br> 卢米亚岛上生存实验的特殊规则。战胜敌人，获取他们的悬赏金，强化自己，战胜更多敌人。<br> 在每次与同级或以上的战斗中获胜后，你可以获得1悬赏金。每场影片你只能获得2个悬赏金。<br> 悬赏金可以用来在购买黑色幸存者系列升级与物品时充当1xp使用。</p><p>C+1200<br> 生体实验<br> C级时，你可以根据末尾处的实验体表格，选择将身体向某位实验体改造，并获得他们的能力。并且仅开放此实验体的技能树。<br> 如无特殊说明购买价格为C+1200</p><p>B+2400<br> 死亡循环</p><p>特性：生存实验（升级），基因感知，实验体物品栏，武器技能</p><p>生存实验（升级）：<br> 卢米亚岛上生存的实验愈发严酷，你不断地去死，救活并清除记忆，再度去死。但是源自于基因的VF能量愈发强盛<br> 只要保持充足的饮食与水分，你的身体就将其转化为VF能量，治愈你的伤势。<br> 在D级的生存实验特性的基础上，你再获得2点快速医疗。但是你不能获得无需饮食，若是你有无需饮食，则改为获得快疗上的8点医疗点<br> 此外，你获得1点异常点数恢复（医疗点24）可以治愈三至四档异常点</p><p>基因感知：<br> 对于敌人与环境的感知字面意义上的刻在你的dna里，在VF能量的作用下仿佛周围的环境在你脑中变成了moba的模样，用俯视角巨细无遗地观察着周围。这是一种强感知方式。</p><p>实验体物品栏：<br> 你获得100立方米的储物空间，不能装独立单位、放入/取出物品至少是一个花招动作。</p><p>武器技能：根据你与C级选择的武器，你获得对应的技能，在获得一项后，无法再获得其他这个能力带来的效果：</p><p>自动手枪/左轮手枪：移动重载<br> 你的武器现在获得无限子弹，并且你的移动速度增加15米。若是你的武器已经拥有无限子弹，那么改为获得射击检定上的1点额外附加成功。<br> 此外，你每回合额外获得2点仅能用于进行射击攻击检定的AP。</p><p>步枪：枪械过热<br> 在战斗中每经过一轮，你获得3点的武器伤害提升。最多只能获得5轮（15点武器伤害提升）的加成。</p><p>狙击/来复枪：狙击强化<br> 你的武器现在获得超级贯穿</p><p>附录：</p><p>C级实验体选择：</p><p>编号14M-RFT11 阿雅</p><p>人们的价值观会决定他们成为什么样的人。她的价值观可以用一个词来概括——正义</p><p>特性：枪械专精，阿雅之正义</p><p>枪械专精：购买时选择自动手枪，左轮手枪，步枪或狙击/来复枪中的一种，你在使用这种武器进行攻击检定时的加骰提升一级，最高为8加骰。同时仅有在使用该类武器时<br> 阿雅下属的专属技艺才会生效</p><p>阿雅之正义<br> 效果：一场影片一次：在你即将遭受攻击的时候，你可以使用反射动作，随后你获得6点临时生命值。</p><p>阿雅技能树：<br> 价格均为标准技艺价格：D+500/C+1000/B+2000<br> D级技艺：二连射<br> 你对攻击射程内的单位进行一次二连射，消耗2发子弹。随后，在本次攻击中你在射击上获得2点增强加值，同时你的武器获得连射特性。<br> 若是已经有（短点射/长点射/连射），则改为获得（1/2/3）点高速。</p><p>C级技艺：稳定射击<br> 你在移动的同时对至多3个敌方单位进行扫射。这次攻击选择3个目标时会额外对每个目标造成持续一轮的3点多次攻击减值。此外，这次攻击额外增加5威猛与2点射击上的增强加值。</p><p>C级技艺：转向<br> 在即将遭受攻击时，你可以反射动作消耗下个回合的一个标准动作，进行至多等同于一个移动距离的移动，这视为一次打断。<br> 同时，你获得2点AP，仅能用于使用带有射击攻击检定的技艺。</p><p>B级技艺：空弹！<br> 你花费全回合动作与3点意志力，将手中的枪举向天空，蓄力发射空弹，恐吓范围内的所有目标。<br> 对于半径为武器射程的圆形区域内的所有敌方单位进行一次远程攻击，敌方单位以意志豁免对抗你的射击检定，并在此次对抗上获得4点士气减值。此次攻击你的攻击检定成功数增加一半。<br> 同时，本次攻击附带成功数的恐惧异常点数。</p><p>编号 17M-RFT31 佐藤雪</p><p>完美，可是转瞬即逝的————雪</p><p>特性：剑术专精，武装式</p><p>剑术专精：你在使用剑或是双剑进行攻击检定时的加骰提升一级，最高为8加骰。同时仅有在剑或是双剑时雪的专属技艺才会生效</p><p>武装式：每场场景，你都会获得四个武装式纽扣。在持有纽扣时，在你的攻击成功命中目标后，你会额外造成4点追加伤害，随后消耗一枚纽扣。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',36)])])}const m=a(o,[["render",s]]);export{f as __pageData,m as default};
